#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor object from the source_buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>> adaptor(source_buffer);

    // Check if the requested bytes_to_read is within the available data
    if (bytes_to_read > adaptor.size()) {
        throw std::runtime_error("Requested read size exceeds available buffer data");
    }

    // Create a destination vector and use the read function to copy data
    std::vector<uint8_t> destination(bytes_to_read);
    adaptor.read(destination.data(), bytes_to_read);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a buffer_adaptor object from the dest_buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(dest_buffer);

    // Check if the buffer has enough space, if not, handle appropriately
    size_t required_space = adaptor.size() + source_data.size();
    if (dest_buffer.capacity() < required_space) {
        // Resize the buffer if needed (using std::vector's resize capability)
        dest_buffer.resize(required_space);
    }

    // Use the write function to copy data from source_data to the buffer
    adaptor.write(source_data.data(), source_data.size());
}
