bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer_adaptor for the given buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Check available space using buffer_adaptor
    // Note: The available space is calculated as total buffer size minus current write position
    auto available_space = adaptor.size() - (adaptor.write_ - adaptor.read_);

    // Calculate required space: header (4 bytes) + items (each uint32_t is 4 bytes)
    auto required_space = sizeof(header) + (items.size() * sizeof(uint32_t));

    // If insufficient space, return false
    if (available_space < required_space) {
        return false;
    }

    // Get the write pointer using buffer_adaptor
    auto* write_ptr = adaptor.write_ptr();

    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Use binary_stream to write header and items
    // Write header using operator<<
    stream << header;

    // Write container data using write_container
    stream.write_container(items);

    // Return true if successful
    return true;
}
