#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with the specified element count
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate allocation operations that internally trigger pop()
    int* allocated1 = allocator.allocate(1);
    int* allocated2 = allocator.allocate(2);
    int* allocated3 = allocator.allocate(3);

    // Demonstrate deallocation operations that internally trigger push()
    allocator.deallocate(allocated1);
    allocator.deallocate(allocated2);
    allocator.deallocate(allocated3);

    // Show additional allocation/deallocation to demonstrate free list cycling
    int* allocated4 = allocator.allocate(4);
    allocator.deallocate(allocated4);

    int* allocated5 = allocator.allocate(5);
    allocator.deallocate(allocated5);

    // Demonstrate that when free list is exhausted, it falls back to new()
    // This would happen if we exceed the preallocated element_count
