    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor object
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> writer(buffer);

    // Check available space before writing
    if (writer.free() < input_data.size()) {
        // Resize buffer if needed (implementation depends on specific requirements)
        // For this example, we'll assume the buffer can handle the data
        buffer.resize(input_data.size());
    }

    // Write data to buffer
    writer.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor object
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer);

    // Check available data size
    if (reader.size() == 0) {
        return {};
    }

    // Read data back from buffer
    std::vector<uint8_t> output_data(reader.size());
    reader.read(output_data.data(), output_data.size());

    return output_data;
